qry:select.qry:xquery:
for $r in table('
	select d_empresa from org03_empresas where oi_empresa= {#FILTRO:@oi_empresa}
')/ROWS/ROW

					for $r in table('SELECT 	e_numero_legajo, d_ape_y_nom , oi_licencia_per, 
								PER02_LICEN_PER.oi_licencia, 
								PER02_LICEN_PER.oi_personal_emp, 
								PER02_LICEN_PER.f_inicio,
							 PER02_LICEN_PER.f_fin, 
							 e_cant_dias =   PER02_LICEN_PER.e_cant_dias , 
							 e_max_dias_anio = isnull(PER16_LICENCIAS.e_max_dias_anio ,0) ,
							 e_max_dias_lic = isnull(PER16_LIC_CONV.e_max_dias_lic ,0)

          from per01_personal, per02_personal_emp,  
          			PER02_LICEN_PER, org02_estruc_pers, PER16_LIC_CONV     ,PER16_LICENCIAS
					where oi_clase_org = {#FILTRO:@oi_clase_org}
					and org02_estruc_pers.oi_estructura={#PARAM:@id}
					{%? (#FILTRO:@oi_estructura!='') {% AND org02_estruc_pers.oi_estructura={%=#FILTRO:@oi_estructura %} %} {% AND 1=1%} %}
					and PER02_PERSONAL_EMP.oi_empresa = {#FILTRO:@oi_empresa} 						
					and per01_personal.oi_personal =  per02_personal_emp.oi_personal
					and PER02_LICEN_PER.oi_personal_emp =  per02_personal_emp.oi_personal_emp
					and PER02_LICEN_PER.oi_licencia =  PER16_LICENCIAS.oi_licencia
					and PER16_LICENCIAS.oi_licencia *=  PER16_LIC_CONV.oi_licencia
					and PER02_PERSONAL_EMP.oi_personal_emp = org02_estruc_pers.oi_personal_emp				
					{%? (#FILTRO:@f_des!='') {% and PER02_LICEN_PER.f_inicio >= \'{%= #FILTRO:@f_des%}\'%} {% and PER02_LICEN_PER.f_inicio <= GETDATE() %}   %}
					{%? (#FILTRO:@f_has!='') {% and isnull(PER02_LICEN_PER.f_fin,DATEDIFF(day,1,\'{%= #FILTRO:@f_has %}\')) <= \'{%= #FILTRO:@f_has %}\' %} {% and isnull(PER02_LICEN_PER.f_fin,GETDATE()) >= GETDATE() %}  %}					
					{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) %} {%  %} %}							
						')/ROWS/ROW

					for $r in table('SELECT 	e_numero_legajo, d_ape_y_nom , oi_licencia_per, 
								PER02_LICEN_PER.oi_licencia, 
								PER02_LICEN_PER.oi_personal_emp, 
								PER02_LICEN_PER.f_inicio,
							 PER02_LICEN_PER.f_fin, 
							 e_cant_dias =   PER02_LICEN_PER.e_cant_dias , 
							 e_max_dias_anio = isnull(PER16_LICENCIAS.e_max_dias_anio ,0) ,
							 e_max_dias_lic = isnull(PER16_LIC_CONV.e_max_dias_lic ,0)

          from per01_personal, per02_personal_emp,  
          			PER02_LICEN_PER, org02_estruc_pers, PER16_LIC_CONV     ,PER16_LICENCIAS
					where oi_clase_org = {#FILTRO:@oi_clase_org}
					and org02_estruc_pers.oi_estructura={#PARAM:@id}
					and PER02_PERSONAL_EMP.oi_empresa = {#FILTRO:@oi_empresa} 						
					and per01_personal.oi_personal =  per02_personal_emp.oi_personal
				and PER02_LICEN_PER.oi_personal_emp =  per02_personal_emp.oi_personal_emp
					and PER02_LICEN_PER.oi_licencia =  PER16_LICENCIAS.oi_licencia
					and PER16_LICENCIAS.oi_licencia *=  PER16_LIC_CONV.oi_licencia
					and PER02_PERSONAL_EMP.oi_personal_emp = org02_estruc_pers.oi_personal_emp				
					{%? (#FILTRO:@f_des!='') {% and PER02_LICEN_PER.f_inicio >= \'{%= #FILTRO:@f_des%}\'%} {% and PER02_LICEN_PER.f_inicio <= GETDATE() %}   %}
					{%? (#FILTRO:@f_has!='') {% and isnull(PER02_LICEN_PER.f_fin,DATEDIFF(day,1,\'{%= #FILTRO:@f_has %}\')) <= \'{%= #FILTRO:@f_has %}\' %} {% and isnull(PER02_LICEN_PER.f_fin,GETDATE()) >= GETDATE() %}  %}					
					{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) %} {%  %} %}							
						')/ROWS/ROW

for $r in table('
	select d_empresa from org03_empresas where oi_empresa= {#FILTRO:@oi_empresa}
')/ROWS/ROW

		for $r in table('select tmp.e_numero_legajo, 
												tmp.d_ape_y_nom , 
												tmp.oi_licencia_per, 
												tmp.oi_licencia, 
												tmp.oi_personal_emp, 
												tmp.f_inicio,
												tmp.f_fin, 
												e_cant_dias = isnull(tmp.e_cant_dias ,999), 
												e_max_dias_anio = isnull(tmp.e_max_dias_anio ,999),
												tmp.oi_convenio  , 	
												e_max_dias_lic = isnull(PER16_LIC_CONV.e_max_dias_lic ,999)
  								from (SELECT 	e_numero_legajo, d_ape_y_nom , oi_licencia_per, 
													PER02_LICEN_PER.oi_licencia, 
													PER02_LICEN_PER.oi_personal_emp, 
													PER02_LICEN_PER.f_inicio,
													PER02_LICEN_PER.f_fin, 
													e_cant_dias =   PER02_LICEN_PER.e_cant_dias , 
													e_max_dias_anio = isnull(PER16_LICENCIAS.e_max_dias_anio ,0) ,
													ORG18_CATEGORIAS.oi_convenio 
													from per01_personal, per02_personal_emp,   PER02_LICEN_PER, org02_estruc_pers, PER16_LICENCIAS, ORG18_CATEGORIAS
														where oi_clase_org = {%=#FILTRO:@oi_clase_org%}
														and org02_estruc_pers.oi_estructura={%=#PARAM:@id%}
														{%? (#FILTRO:@oi_estructura!='') {% AND org02_estruc_pers.oi_estructura={%=#FILTRO:@oi_estructura %} %} {% AND 1=1%} %}
														and PER02_PERSONAL_EMP.oi_empresa = {%=#FILTRO:@oi_empresa%} 						
														and PER02_LICEN_PER.oi_personal_emp =  per02_personal_emp.oi_personal_emp
														and PER02_LICEN_PER.oi_licencia =  PER16_LICENCIAS.oi_licencia
														and PER02_PERSONAL_EMP.oi_categoria_ult = ORG18_CATEGORIAS.oi_categoria 			
														and PER02_PERSONAL_EMP.oi_personal_emp = org02_estruc_pers.oi_personal_emp 

														and per01_personal.oi_personal = PER02_PERSONAL_EMP.oi_personal
														{%? (#FILTRO:@f_des!='') 
															{% and PER02_LICEN_PER.f_inicio >= \'{%=#FILTRO:@f_des%}\'
															 and PER02_LICEN_PER.f_inicio <= GETDATE() %}  
													  {% %}
													  %}  

														{%? (#FILTRO:@f_has!='') 

														{% and isnull(PER02_LICEN_PER.f_fin,DATEDIFF(day,1,\'{%=#FILTRO:@f_has %}\')) <= \'{%=#FILTRO:@f_has %}\' %} 
														  	  {% %}
														%}																					  

														{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
															{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) 
															%}
													  {% %}
															%}
												) tmp , PER16_LIC_CONV  
									where 	tmp.oi_licencia	*= PER16_LIC_CONV.oi_licencia AND  
													tmp.oi_convenio *= PER16_LIC_CONV.oi_convenio   
			')/ROWS/ROW

		for $r in table('select tmp.e_numero_legajo, 
												tmp.d_ape_y_nom , 
												tmp.oi_licencia_per, 
												tmp.oi_licencia, 
												tmp.oi_personal_emp, 
												tmp.f_inicio,
												tmp.f_fin, 
												e_cant_dias = isnull(tmp.e_cant_dias  ,999), 
												e_max_dias_anio = isnull(tmp.e_max_dias_anio ,999),
												tmp.oi_convenio  , 	
												e_max_dias_lic = isnull(PER16_LIC_CONV.e_max_dias_lic ,999)
  								from (SELECT 	e_numero_legajo, d_ape_y_nom , oi_licencia_per, 
													PER02_LICEN_PER.oi_licencia, 
													PER02_LICEN_PER.oi_personal_emp, 
													PER02_LICEN_PER.f_inicio,
													PER02_LICEN_PER.f_fin, 
													e_cant_dias =   PER02_LICEN_PER.e_cant_dias , 
													e_max_dias_anio = isnull(PER16_LICENCIAS.e_max_dias_anio ,0) ,
													ORG18_CATEGORIAS.oi_convenio 
													from per01_personal, per02_personal_emp,   PER02_LICEN_PER, org02_estruc_pers, PER16_LICENCIAS, ORG18_CATEGORIAS
														where oi_clase_org = {%=#FILTRO:@oi_clase_org%}
														and org02_estruc_pers.oi_estructura={%=#PARAM:@id%}
														and PER02_PERSONAL_EMP.oi_empresa = {%=#FILTRO:@oi_empresa%} 						
														and PER02_LICEN_PER.oi_personal_emp =  per02_personal_emp.oi_personal_emp
														and PER02_LICEN_PER.oi_licencia =  PER16_LICENCIAS.oi_licencia
														and PER02_PERSONAL_EMP.oi_categoria_ult = ORG18_CATEGORIAS.oi_categoria 			
														and PER02_PERSONAL_EMP.oi_personal_emp = org02_estruc_pers.oi_personal_emp 
														and per01_personal.oi_personal = PER02_PERSONAL_EMP.oi_personal
														{%? (#FILTRO:@f_des!='') 
															{% and PER02_LICEN_PER.f_inicio >= \'{%=#FILTRO:@f_des%}\'
															   and PER02_LICEN_PER.f_inicio <= GETDATE() %}  
													 		{% %}
													  %}
														{%? (#FILTRO:@f_has!='') 

														{% and isnull(PER02_LICEN_PER.f_fin,DATEDIFF(day,1,\'{%=#FILTRO:@f_has %}\')) <= \'{%=#FILTRO:@f_has %}\' %} 
														 	  {% %}
														%}																					  

														{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
															{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) 
															%}
													         {% %}
														%}
								) tmp , PER16_LIC_CONV  
									where 	tmp.oi_licencia	*= PER16_LIC_CONV.oi_licencia AND  
													tmp.oi_convenio *= PER16_LIC_CONV.oi_convenio   
			')/ROWS/ROW
